const express=require("express"),cors=require("cors"),fs=require("fs"),path=require("path"),app=express(),PORT=process.env.PORT||5e3,VIEWS_FILE=path.join("/tmp","views.json");app.use(cors({origin:["http://localhost:3000","https://eltriputra4.vercel.app","https://eltri-project.vercel.app"],methods:["GET","POST"],credentials:!0})),app.use(express.json());const readViews=()=>{fs.existsSync(VIEWS_FILE)||fs.writeFileSync(VIEWS_FILE,JSON.stringify({}));const s=fs.readFileSync(VIEWS_FILE,"utf-8");return JSON.parse(s)},writeViews=s=>{fs.writeFileSync(VIEWS_FILE,JSON.stringify(s,null,2))};app.get("/api/views",(s,e)=>{const i=readViews();e.json(i)}),app.get("/api/views/:id",(s,e)=>{const i=readViews(),r=s.params.id.toString();e.json({id:r,views:i[r]||0})}),app.post("/api/views/:id",(s,e)=>{const i=readViews(),r=s.params.id.toString();i[r]=(Number(i[r])||0)+1,writeViews(i),e.json({id:r,views:i[r]})}),app.listen(PORT,()=>{console.log(`✅ Views server running at port ${PORT}`);try{fs.existsSync(VIEWS_FILE)||fs.writeFileSync(VIEWS_FILE,JSON.stringify({}));const s=readViews(),e={...{3:0,10:0,11:0,12:0,13:0,14:0,15:0},...s};writeViews(e),console.log("✏️ Database cloud views.json berhasil disinkronisasikan!")}catch(s){console.log("⚠️ Gagal sinkronisasi data awal:",s.message)}});